### 1. OpenGraph Meta Tags
```typescript
test('should have correct OG tags for public prompt', async ({ page }) => {
  const prompt = await createPublicPrompt();
  await page.goto(`/prompts/${prompt.id}`);

  // Check meta tags
  const ogTitle = await page.locator('meta[property="og:title"]').getAttribute('content');
  const ogDescription = await page.locator('meta[property="og:description"]').getAttribute('content');
  const ogImage = await page.locator('meta[property="og:image"]').getAttribute('content');
  const ogUrl = await page.locator('meta[property="og:url"]').getAttribute('content');

  expect(ogTitle).toBe(prompt.title);
  expect(ogDescription).toBe(prompt.description);
  expect(ogImage).toContain('/api/og/prompt/');
  expect(ogUrl).toContain(`/prompts/${prompt.id}`);
});

test('should have Twitter Card meta tags', async ({ page }) => {
  const prompt = await createPublicPrompt();
  await page.goto(`/prompts/${prompt.id}`);

  const twitterCard = await page.locator('meta[name="twitter:card"]').getAttribute('content');
  const twitterTitle = await page.locator('meta[name="twitter:title"]').getAttribute('content');

  expect(twitterCard).toBe('summary_large_image');
  expect(twitterTitle).toBe(prompt.title);
});
```

